export interface IpcClient {
  call<Action extends IpcActionName>(
    action: Action,
    payload: unknown,
  ): Promise<unknown>;

  callGet<Action extends 'session.next-message'>(
    action: Action,
    query: Record<string, string>,
  ): Promise<unknown>;

  event(eventName: string, payload: unknown): Promise<void>;

  close(): Promise<void>;
}

