10	import { createMockWorkspacePlugin } from '@ax/test-harness';
11	import { workspaceCommitNotifyHandler } from '../workspace-commit-notify.js';
12	
13	// ---------------------------------------------------------------------------
14	// workspace.commit-notify handler — handler-specific tests.
15	//
16	// The bundler pipeline (verify → walk → filter → prepareScratchRepo) is
17	// covered exhaustively by the bundler unit tests
18	// (`packages/ipc-core/src/bundler/__tests__/{filter,scratch,verify,walk}.test.ts`).
19	// The end-to-end commit-notify path against a real workspace-git-server
20	// is covered by the Phase 3 canary scenarios in
21	// `presets/k8s/src/__tests__/acceptance.test.ts`.
22	//
23	// What's left for THIS file: handler-specific concerns the bundler
24	// tests can't see and the canary doesn't isolate cleanly.
25	//   - Empty-bundle short-circuit (no apply, no bundler call).
26	//   - Schema validation (400 VALIDATION on malformed wire).
27	//   - Backend gate (Phase 3 wire requires
28	//     workspace:export-baseline-bundle to be registered; otherwise
29	//     the handler refuses up front rather than silently mis-handling
30	//     subsequent applies).
31	// ---------------------------------------------------------------------------
32	
33	interface Env {
34	  bus: HookBus;
35	  ctx: AgentContext;
36	}
37	
38	async function makeEnv(extraPlugins: Plugin[] = []): Promise<Env> {
39	  const bus = new HookBus();
40	  await bootstrap({
41	    bus,
42	    plugins: [createMockWorkspacePlugin(), ...extraPlugins],
43	    config: {},
44	  });
45	  const ctx = makeAgentContext({
46	    sessionId: 'wcn-test',
47	    agentId: 'wcn-agent',
48	    userId: 'wcn-user',
49	  });
50	  return { bus, ctx };
51	}
52	
53	describe('workspace.commit-notify handler — empty bundle', () => {
54	  it('short-circuits to accepted:true with parentVersion preserved', async () => {
55	    const { bus, ctx } = await makeEnv();
56	    const result = await workspaceCommitNotifyHandler(
57	      {
58	        parentVersion: 'v-existing',
59	        reason: 'turn',
60	        bundleBytes: '',
61	      },
62	      ctx,
63	      bus,
64	    );
65	    expect(result.status).toBe(200);
66	    const body = result.body as { accepted: true; version: string };
67	    expect(body.accepted).toBe(true);
68	    expect(body.version).toBe('v-existing');
69	  });
70	
71	  it('short-circuits to accepted:true even with null parentVersion', async () => {
72	    const { bus, ctx } = await makeEnv();
73	    const result = await workspaceCommitNotifyHandler(
74	      {
75	        parentVersion: null,
76	        reason: 'turn',
77	        bundleBytes: '',
78	      },
79	      ctx,
80	      bus,
81	    );
82	    expect(result.status).toBe(200);
83	    expect((result.body as { accepted: boolean }).accepted).toBe(true);
84	  });
85	});
