87	describe('workspace.commit-notify handler — schema validation', () => {
88	  it('malformed request (missing bundleBytes) → 400 VALIDATION', async () => {
89	    const { bus, ctx } = await makeEnv();
90	    const result = await workspaceCommitNotifyHandler(
91	      {
92	        parentVersion: null,
93	        reason: 'turn',
94	        // Missing bundleBytes — schema rejects.
95	      },
96	      ctx,
97	      bus,
