248	    // and prepareScratchRepo will throw. The handler catches that and
249	    // returns accepted:false (NOT a 500), proving the gate let us
250	    // through and the error surfaced as a normal "baseline drift"
251	    // outcome.
252	    const probe: Plugin = {
253	      manifest: {
254	        name: '@ax/test-bundle-probe',
255	        version: '0.0.0',
256	        registers: [
257	          'workspace:apply-bundle',
258	          'workspace:export-baseline-bundle',
259	        ],
