283	    const { bus, ctx } = await makeEnv([probe]);
284	    const result = await workspaceCommitNotifyHandler(
285	      {
286	        parentVersion: null,
287	        reason: 'turn',
288	        bundleBytes: 'UEFDSwAAAAA=',
289	      },
290	      ctx,
291	      bus,
292	    );
293	    // Gate passed; handler reached prepareScratchRepo; bundle was
294	    // garbage so it failed gracefully as accepted:false (not a 500).
