1	// ---------------------------------------------------------------------------
2	// Regression test: concurrent attachments:commit must not drop chat turns.
3	//
4	// Production scenario that was lost before this fix:
5	//
6	//   1. Chat turn T1 lands: runner calls workspace.commit-notify with
7	//      parentVersion=V0. Host pushes V1 (turn commit), returns accepted:true.
8	//      Runner advances its local baseline to V1.
9	//   2. CONCURRENT: An attachment upload calls attachments:commit →
10	//      workspace:apply. The host advances the SAME mirror to V2 (an
11	//      attachment file on a disjoint path, child of V1). This is out-of-band
12	//      from the runner's perspective.
13	//   3. Chat turn T2 lands: runner calls workspace.commit-notify with
14	//      parentVersion=V1. The host's mirror head is NOW V2 (not V1).
15	//
16	//   BEFORE THE FIX: exportBaselineBundle threw a raw Error and the handler
17	//   returned 500. The runner treated 500 as a network error, kept the bundle
18	//   accumulating, and every subsequent turn re-sent the same stale bundle →
19	//   permanent 500 loop. The transcript was truncated on reload.
20	//
21	//   AFTER THE FIX (Tasks 1-4):
22	//     - git-engine.ts's exportBaselineBundle detects mirror head ≠ requested
23	//       version and throws PluginError{code:'parent-mismatch'} carrying
24	//       actualParent=V2 and baselineBundleBytes=<bundle@V2>.
25	//     - workspace-commit-notify.ts handler catches that error and returns
26	//       status 200, accepted:false, actualParent, baselineBundleBytes.
27	//     - runner's resyncBaselineAndReplay fetches the bundle, rebases T2 onto
28	//       V2, and retries → accepted:true with parent=V2. Both the attachment
29	//       file AND the turn file are in the workspace.
30	//
31	// What this test validates (host-side integration level):
32	//
33	//   PART A (host): Real GitEngine + real exportBaselineBundle. Drives the full
34	//   V1→out-of-band-V2→exportBaselineBundle(V1) path and asserts the engine
35	//   returns parent-mismatch with actualParent=V2 and non-empty bundleBytes.
36	//
37	//   PART B (full loop): Feeds the baselineBundleBytes from PART A into a
38	//   runner-style repo via raw git operations (matching the exact git commands
39	//   that resyncBaselineAndReplay executes). Then calls applyBundle with
40	//   parent=V2 on the real engine and asserts: (a) accepted, (b) both the
41	//   attachment file (V2) and the turn file (T2) are visible in the mirror.
42	//
43	// Pre-fix failure mode of this test:
44	//   PART A would fail: exportBaselineBundle would NOT return a PluginError;
45	//   instead it would throw a plain Error("mirror head … concurrent writer or
46	//   stale version") OR return successfully with the wrong (stale) bundle. The
47	//   `expect(err).toBeInstanceOf(PluginError)` assertion would fail.
48	//   PART B would never be reached.
49	//
50	// Coverage boundary:
51	//   The full runner re-sync loop (the bounded retry in main.ts) is NOT
52	//   exercised here — that path requires driving the full runner process.
53	//   It is covered by the manual cluster re-walk in the plan's Verification
54	//   section. The raw git rebase in PART B is the same git invocation sequence
55	//   that resyncBaselineAndReplay uses, so the object-store plumbing is
56	//   equivalent.
57	// ---------------------------------------------------------------------------
58	
59	import { spawn } from 'node:child_process';
60	import * as fs from 'node:fs/promises';
61	import { mkdtempSync } from 'node:fs';
62	import { tmpdir } from 'node:os';
63	import { dirname, join } from 'node:path';
64	import { afterEach, beforeEach, describe, expect, it } from 'vitest';
65	import { asWorkspaceVersion, PluginError } from '@ax/core';
66	import {
67	  createWorkspaceGitServer,
68	  type WorkspaceGitServer,
69	} from '../../server/index.js';
70	import { createGitEngine, type GitEngine } from '../git-engine.js';
71	import { createMirrorCache, type MirrorCache } from '../mirror-cache.js';
72	import { createRepoLifecycleClient } from '../repo-lifecycle.js';
73	
74	// ---------------------------------------------------------------------------
75	// Test helpers
76	// ---------------------------------------------------------------------------
77	
78	interface SpawnResult {
79	  code: number | null;
80	  stdout: string;
81	  stderr: string;
82	}
83	
84	async function git(
85	  args: readonly string[],
86	  cwd?: string,
87	  env?: NodeJS.ProcessEnv,
88	): Promise<SpawnResult> {
89	  return new Promise((resolve, reject) => {
90	    const child = spawn('git', [...args], {
91	      cwd,
92	      env: env ?? process.env,
93	    });
94	    let stdout = '';
95	    let stderr = '';
96	    child.stdout.on('data', (c: Buffer) => (stdout += c.toString('utf8')));
97	    child.stderr.on('data', (c: Buffer) => (stderr += c.toString('utf8')));
98	    child.once('error', reject);
99	    child.once('close', (code) => resolve({ code, stdout, stderr }));
100	  });
101	}
102	
103	/**
104	 * Like `git()`, but throws on a non-zero exit so an environmental git
105	 * failure (missing binary, EROFS tempdir, etc.) surfaces at the failing
106	 * command rather than as a confusing downstream error.
107	 */
108	async function gitOrThrow(
109	  args: readonly string[],
110	  cwd?: string,
111	  env?: NodeJS.ProcessEnv,
112	): Promise<SpawnResult> {
113	  const r = await git(args, cwd, env);
114	  if (r.code !== 0) {
115	    throw new Error(`git ${args.join(' ')} exited ${r.code}: ${r.stderr}`);
116	  }
117	  return r;
118	}
119	
120	// Matches git-engine.ts's BASELINE_ENV (must stay in sync — determinism contract).
121	const SIM_BASELINE_ENV: NodeJS.ProcessEnv = {
122	  ...process.env,
123	  GIT_AUTHOR_NAME: 'ax-runner',
124	  GIT_AUTHOR_EMAIL: 'ax-runner@example.com',
125	  GIT_COMMITTER_NAME: 'ax-runner',
126	  GIT_COMMITTER_EMAIL: 'ax-runner@example.com',
127	  GIT_AUTHOR_DATE: '1970-01-01T00:00:00Z',
128	  GIT_COMMITTER_DATE: '1970-01-01T00:00:00Z',
129	};
130	
131	/**
132	 * Build a thin bundle (baseline..main + main ref) from a runner-style repo.
133	 * Returns base64 bytes.
134	 */
135	async function buildTurnBundle(repoDir: string): Promise<string> {
136	  return new Promise<string>((resolve, reject) => {
137	    const child = spawn('git', [
138	      '-C', repoDir,
139	      'bundle', 'create', '-',
140	      'baseline..main', 'main',
141	    ]);
142	    const chunks: Buffer[] = [];
143	    let stderr = '';
144	    child.stdout.on('data', (c: Buffer) => chunks.push(c));
145	    child.stderr.on('data', (c: Buffer) => (stderr += c.toString('utf8')));
146	    child.once('error', reject);
147	    child.once('close', (code) =>
148	      code === 0
149	        ? resolve(Buffer.concat(chunks).toString('base64'))
150	        : reject(new Error(`bundle exit=${code}: ${stderr}`)),
151	    );
152	  });
153	}
154	
155	/**
156	 * Build a runner-style working tree on top of an empty-tree baseline.
157	 * Returns { wt: <path>, baselineCommit: <oid> }.
158	 */
159	async function buildRunnerWorkspace(args: {
160	  root: string;
161	  turnFiles: Record<string, string>;
162	}): Promise<{ wt: string; baselineCommit: string }> {
163	  const { root, turnFiles } = args;
164	
165	  // 1. Build the deterministic empty-tree baseline (mirrors buildEmptyBaselineBundle
166	  //    in git-engine.ts — fixed dates, fixed author env, core.fileMode=false).
167	  const baselineDir = join(root, 'baseline');
168	  await fs.mkdir(baselineDir, { recursive: true });
169	  await gitOrThrow(['init', '-b', 'main', baselineDir], undefined, SIM_BASELINE_ENV);
170	  await gitOrThrow(['-C', baselineDir, 'config', 'core.fileMode', 'false'], undefined, SIM_BASELINE_ENV);
171	  await gitOrThrow(['-C', baselineDir, 'commit', '--allow-empty', '-m', 'baseline'], undefined, SIM_BASELINE_ENV);
172	  const baselineBundle = join(root, 'baseline.bundle');
173	  await gitOrThrow(['-C', baselineDir, 'bundle', 'create', baselineBundle, 'main'], undefined, SIM_BASELINE_ENV);
174	  const baselineOid = (await gitOrThrow(['-C', baselineDir, 'rev-parse', 'HEAD'], undefined, SIM_BASELINE_ENV)).stdout.trim();
175	
176	  // 2. Clone into working tree.
177	  const wt = join(root, 'wt');
178	  await gitOrThrow(['clone', '--branch', 'main', baselineBundle, wt]);
179	  await gitOrThrow(['-C', wt, 'update-ref', 'refs/heads/baseline', 'HEAD']);
180	  await gitOrThrow(['-C', wt, 'config', 'user.name', 'ax-runner']);
181	  await gitOrThrow(['-C', wt, 'config', 'user.email', 'ax-runner@example.com']);
182	
183	  // 3. Write turn files, then stage + commit them (this is the turn commit
184	  //    on top of the baseline; the caller bundles `baseline..main` from it).
185	  for (const [p, content] of Object.entries(turnFiles)) {
186	    const abs = join(wt, p);
187	    await fs.mkdir(join(wt, dirname(p)), { recursive: true });
188	    await fs.writeFile(abs, content);
189	  }
190	  await gitOrThrow(['-C', wt, 'add', '-A']);
191	  await gitOrThrow(['-C', wt, 'commit', '-m', 'turn']);
192	
193	  return { wt, baselineCommit: baselineOid };
194	}
195	
196	// ---------------------------------------------------------------------------
197	// Harness
198	// ---------------------------------------------------------------------------
199	
200	const TOKEN = 'concurrent-attach-regression-token';
201	
202	interface Harness {
203	  server: WorkspaceGitServer;
204	  engine: GitEngine;
205	  mirrorCache: MirrorCache;
206	  repoRoot: string;
207	  baseUrl: string;
208	}
209	
210	async function bootHarness(): Promise<Harness> {
211	  const repoRoot = mkdtempSync(join(tmpdir(), 'ax-concurrent-attach-repos-'));
212	  const server = await createWorkspaceGitServer({
213	    repoRoot,
214	    host: '127.0.0.1',
215	    port: 0,
216	    token: TOKEN,
217	  });
218	  const baseUrl = `http://127.0.0.1:${server.port}`;
219	  const mirrorCache = createMirrorCache();
220	  const lifecycleClient = createRepoLifecycleClient({ baseUrl, token: TOKEN });
221	  const engine = createGitEngine({ baseUrl, token: TOKEN, mirrorCache, lifecycleClient });
222	  return { server, engine, mirrorCache, repoRoot, baseUrl };
223	}
224	
225	async function teardown(h: Harness): Promise<void> {
226	  await h.engine.shutdown();
227	  await h.mirrorCache.shutdown();
228	  await h.server.close();
229	  await fs.rm(h.repoRoot, { recursive: true, force: true });
230	}
231	
232	let harness: Harness;
233	
234	beforeEach(async () => {
235	  harness = await bootHarness();
236	});
237	
238	afterEach(async () => {
239	  await teardown(harness);
240	});
241	
242	// ---------------------------------------------------------------------------
243	// The regression test
244	// ---------------------------------------------------------------------------
245	
246	describe('git-engine — concurrent attachments:commit must not drop chat turns', () => {
247	  it(
248	    'PART A: exportBaselineBundle(V1) returns parent-mismatch+actualParent+bundle when mirror advanced to V2 out-of-band',
249	    async () => {
250	      // -----------------------------------------------------------------------
251	      // Setup: drive the host mirror through:
252	      //   V0 (empty baseline) → V1 (chat turn T1 accepted)
253	      //                       → V2 (concurrent attachment apply, disjoint path)
254	      // The runner still holds parentVersion=V1 when it sends its NEXT turn,
255	      // so its next commit-notify exports baseline at V1 — but the mirror is
256	      // already at V2. PART A asserts that mismatch is reported as a re-sync
257	      // signal, not a 500. (We don't need a runner T2 bundle here:
258	      // exportBaselineBundle is the trigger, the mirror state is what matters.)
259	      // -----------------------------------------------------------------------
260	      const wsId = 'ws-concurrent-attach-regression';
261	      const tmpRoot = mkdtempSync(join(tmpdir(), 'ax-runner-sim-'));
262	
263	      try {
264	        // --- Step 1: Simulate runner's first turn (T1) against empty workspace.
265	        // Build runner workspace with a chat turn file (.ax/projects/…/t1.jsonl).
266	        const { wt: wt1, baselineCommit } = await buildRunnerWorkspace({
267	          root: join(tmpRoot, 'turn1'),
268	          turnFiles: {
269	            '.ax/projects/proj1/t1.jsonl': '{"role":"assistant","text":"hello"}\n',
270	          },
271	        });
272	
273	        const t1BundleB64 = await buildTurnBundle(wt1);
274	
275	        // Apply T1 to the host engine → V1.
276	        const r1 = await harness.engine.applyBundle(wsId, {
277	          bundleBytes: t1BundleB64,
278	          baselineCommit,
279	          parent: null,
280	          reason: 'turn 1',
281	        });
282	        const v1 = r1.version as string;
283	        expect(v1).toMatch(/^[0-9a-f]{40}$/);
284	
285	        // --- Step 2: Out-of-band attachment apply → V2.
286	        // Simulate what attachments:commit → workspace:apply does:
287	        // it calls apply() with parent=V1, touching a disjoint path.
288	        const r2 = await harness.engine.apply(wsId, {
289	          changes: [
290	            {
291	              path: '.ax/uploads/img001.png',
292	              kind: 'put',
293	              content: new TextEncoder().encode('\x89PNG\r\n'),
294	            },
295	          ],
296	          parent: asWorkspaceVersion(v1),
297	          reason: 'attachment upload',
298	        });
299	        const v2 = r2.version as string;
300	        expect(v2).toMatch(/^[0-9a-f]{40}$/);
301	        expect(v2).not.toBe(v1);
302	
303	        // ---------------------------------------------------------------------
304	        // PART A: Call exportBaselineBundle(wsId, { version: V1 }).
305	        // The mirror is now at V2. This MUST throw PluginError{code:'parent-mismatch'}
306	        // with cause.actualParent===V2 and cause.baselineBundleBytes non-empty.
307	        //
308	        // PRE-FIX behaviour: exportBaselineBundle would call exportMirrorBundle
309	        // which calls git rev-parse + verifies headOid===oid. When oid !== head,
310	        // the OLD code threw a plain Error("mirror head … concurrent writer"),
311	        // NOT a PluginError — so the handler escalated to 500 and the runner
312	        // looped forever. The pre-fix exportMirrorBundle did NOT bundle the
313	        // current head, so the runner had no way to resync.
314	        //
315	        // POST-FIX behaviour: exportBaselineBundle detects oid !== head, bundles
316	        // the CURRENT head (V2), and throws PluginError{code:'parent-mismatch'}
317	        // with cause.actualParent=V2 and cause.baselineBundleBytes=<bundle@V2>.
318	        // ---------------------------------------------------------------------
319	        const err = await harness.engine
320	          .exportBaselineBundle(wsId, { version: asWorkspaceVersion(v1) })
321	          .catch((e: unknown) => e);
322	
323	        // The export MUST fail — accepted at V1 when mirror is at V2 is wrong.
324	        expect(err).toBeInstanceOf(PluginError);
